167→    /**
168→     * 提交考试：评分 → 保存答题明细 → 更新记录
169→     */
170→    @Transactional(rollbackFor = Exception.class)
171→    public ExamSubmitResponse submitExam(ExamSubmitRequest req, Long userId) {
172→        // 1. 校验记录
173→        ExamRecord record = examRecordMapper.selectById(req.getRecordId());
174→        if (record == null) {
175→            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
176→        }
177→        if (!record.getUserId().equals(userId)) {
178→            throw new BizException(ErrorCode.FORBIDDEN);
179→        }
180→        if (record.getStatus() != RecordStatus.IN_PROGRESS) {
181→            throw new BizException(ErrorCode.RECORD_ALREADY_SUBMITTED);
182→        }
183→
184→        // 2. 判断是否超时
185→        Exam exam = examMapper.selectById(record.getExamId());
186→        RecordStatus status;
187→        if (exam.getTimeLimitMin() != null && exam.getTimeLimitMin() > 0
188→                && Duration.between(record.getStartTime(), LocalDateTime.now()).toMinutes() > exam.getTimeLimitMin()) {
189→            status = RecordStatus.TIMEOUT;
190→        } else {
191→            status = RecordStatus.SUBMITTED;
192→        }
193→
194→        // 3. 获取本次考试抽中的题目
195→        List<ExamRecordQuestion> recordQuestions = examRecordQuestionMapper.selectList(
196→                new LambdaQueryWrapper<ExamRecordQuestion>()
197→                        .eq(ExamRecordQuestion::getRecordId, req.getRecordId()));
198→        List<Long> drawnQuestionIds = recordQuestions.stream()
199→                .map(ExamRecordQuestion::getQuestionId)
200→                .collect(Collectors.toList());
201→
202→        // 4. 查询题目详情
203→        Map<Long, QuestionBank> questionMap = questionBankMapper.selectBatchIds(drawnQuestionIds)
204→                .stream()
205→                .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));
206→
207→        // 5. 评分
208→        int totalQuestions = drawnQuestionIds.size();
209→        BigDecimal pointsPerQuestion = new BigDecimal(100)
210→                .divide(new BigDecimal(totalQuestions), 2, RoundingMode.HALF_UP);
211→        int correctCount = 0;
212→
213→        for (AnswerItem item : req.getAnswers()) {
214→            QuestionBank question = questionMap.get(item.getQuestionId());
215→            boolean isCorrect = question != null && item.getAnswer().equals(question.getCorrectAnswer());
216→            if (isCorrect) {
217→                correctCount++;
218→            }
219→
220→            // 保存答题明细
221→            AnswerDetail detail = AnswerDetail.builder()
222→                    .recordId(req.getRecordId())
223→                    .questionId(item.getQuestionId())
224→                    .userAnswer(item.getAnswer())
225→                    .isCorrect(isCorrect)
226→                    .build();
227→            answerDetailMapper.insert(detail);
228→        }
229→
230→        BigDecimal score = pointsPerQuestion.multiply(new BigDecimal(correctCount));
231→
232→        // 6. 更新考试记录
233→        record.setScore(score);
234→        record.setEndTime(LocalDateTime.now());
235→        record.setStatus(status);
236→        examRecordMapper.updateById(record);
237→
238→        log.info("[exam] userId={} submitted recordId={}, score={}, status={}",
239→                userId, req.getRecordId(), score, status.getValue());
240→
241→        // 7. 构建响应
242→        ExamSubmitResponse response = new ExamSubmitResponse();
243→        response.setScore(score);
244→        response.setStatus(status.getValue());
245→        return response;
246→    }
