372→     */
373→    private long countCompletedRecords(Long examId, Long userId) {
374→        return examRecordMapper.selectCount(
375→                new LambdaQueryWrapper<ExamRecord>()
376→                        .eq(ExamRecord::getExamId, examId)
377→                        .eq(ExamRecord::getUserId, userId)
378→                        .in(ExamRecord::getStatus, RecordStatus.SUBMITTED, RecordStatus.TIMEOUT));
