402→    private ExamDetailResponse buildExamDetailResponse(Exam exam, Long userId) {
403→        ExamDetailResponse resp = new ExamDetailResponse();
404→        resp.setId(exam.getId());
405→        resp.setTitle(exam.getTitle());
406→        resp.setStatus(exam.getStatus().getValue());
407→        resp.setTimeLimitMin(exam.getTimeLimitMin());
408→        resp.setQuestionCount(exam.getQuestionCount());
409→        resp.setMaxAttempts(exam.getMaxAttempts());
410→        resp.setShowAnswer(exam.getShowAnswer());
411→        resp.setShowAnalysis(exam.getShowAnalysis());
412→        resp.setAccessMode(exam.getAccessMode().getValue());
413→
414→        // 计算剩余次数
415→        if (exam.getMaxAttempts() == null || exam.getMaxAttempts() == 0) {
416→            resp.setRemainingAttempts(null);
417→        } else {
418→            long completed = countCompletedRecords(exam.getId(), userId);
419→            resp.setRemainingAttempts(Math.max(0, exam.getMaxAttempts() - (int) completed));
420→        }
421→        return resp;
422→    }
