package com.exam.service;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.exam.dto.QuestionBatchRequest;
import com.exam.dto.QuestionCreateRequest;
import com.exam.dto.QuestionItem;
import com.exam.entity.Exam;
import com.exam.entity.QuestionBank;
import com.exam.enums.ExamStatus;
import com.exam.exception.BizException;
import com.exam.exception.ErrorCode;
import com.exam.mapper.ExamMapper;
import com.exam.mapper.QuestionBankMapper;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.ArrayList;
import java.util.List;

/**
 * 题目管理服务
 */
@Slf4j
@Service
public class QuestionService {

    private final QuestionBankMapper questionBankMapper;
    private final ExamMapper examMapper;

    public QuestionService(QuestionBankMapper questionBankMapper, ExamMapper examMapper) {
        this.questionBankMapper = questionBankMapper;
        this.examMapper = examMapper;
    }

    /**
     * 查询指定试卷的题目列表，按排序号升序
     */
    public List<QuestionBank> list(Long examId) {
        return questionBankMapper.selectList(
                new LambdaQueryWrapper<QuestionBank>()
                        .eq(QuestionBank::getExamId, examId)
                        .orderByAsc(QuestionBank::getSortOrder));
    }

    /**
     * 创建单道题目
     */
    public QuestionBank create(Long examId, QuestionCreateRequest req) {
        checkExamDraft(examId);
        int maxSort = getMaxSortOrder(examId);
        QuestionBank question = QuestionBank.builder()
                .examId(examId)
                .content(req.getContent())
                .optionA(req.getOptionA())
                .optionB(req.getOptionB())
                .optionC(req.getOptionC())
                .optionD(req.getOptionD())
                .correctAnswer(req.getCorrectAnswer())
                .analysis(req.getAnalysis())
                .sortOrder(maxSort + 1)
                .build();
        questionBankMapper.insert(question);
        return question;
    }

    /**
     * 批量导入题目
     */
    @Transactional(rollbackFor = Exception.class)
    public int batchCreate(Long examId, QuestionBatchRequest req) {
        checkExamDraft(examId);
        int maxSort = getMaxSortOrder(examId);
        List<QuestionItem> items = req.getQuestions();
        for (QuestionItem item : items) {
            maxSort++;
            QuestionBank question = QuestionBank.builder()
                    .examId(examId)
                    .content(item.getContent())
                    .optionA(item.getOptionA())
                    .optionB(item.getOptionB())
                    .optionC(item.getOptionC())
                    .optionD(item.getOptionD())
                    .correctAnswer(item.getCorrectAnswer())
                    .analysis(item.getAnalysis())
                    .sortOrder(maxSort)
                    .build();
            questionBankMapper.insert(question);
        }
        log.info("[question] batch import examId={}, count={}", examId, items.size());
        return items.size();
    }

    /**
     * 更新题目
     */
    public void update(Long questionId, QuestionCreateRequest req) {
        QuestionBank question = questionBankMapper.selectById(questionId);
        if (question == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }
        checkExamDraft(question.getExamId());
        question.setContent(req.getContent());
        question.setOptionA(req.getOptionA());
        question.setOptionB(req.getOptionB());
        question.setOptionC(req.getOptionC());
        question.setOptionD(req.getOptionD());
        question.setCorrectAnswer(req.getCorrectAnswer());
        question.setAnalysis(req.getAnalysis());
        questionBankMapper.updateById(question);
    }

    /**
     * 删除题目
     */
    public void delete(Long questionId) {
        QuestionBank question = questionBankMapper.selectById(questionId);
        if (question == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }
        checkExamDraft(question.getExamId());
        questionBankMapper.deleteById(questionId);
    }

    /**
     * 校验试卷是否为草稿状态，非草稿抛出异常
     */
    private void checkExamDraft(Long examId) {
        Exam exam = examMapper.selectById(examId);
        if (exam == null) {
            throw new BizException(ErrorCode.NOT_FOUND);
        }
        if (exam.getStatus() != ExamStatus.DRAFT) {
            throw new BizException(ErrorCode.EXAM_NOT_DRAFT);
        }
    }

    /**
     * 获取指定试卷当前最大排序号，无题目时返回 0
     */
    private int getMaxSortOrder(Long examId) {
        LambdaQueryWrapper<QuestionBank> wrapper = new LambdaQueryWrapper<QuestionBank>()
                .eq(QuestionBank::getExamId, examId)
                .orderByDesc(QuestionBank::getSortOrder)
                .last("LIMIT 1");
        QuestionBank last = questionBankMapper.selectOne(wrapper);
        return last == null ? 0 : last.getSortOrder();
    }
}

