import { Outlet, createFileRoute, redirect } from "@tanstack/react-router"
import { getToken } from "@/lib/auth"
import { useAuth } from "@/hooks/use-auth"
import { Header } from "@/components/layout/header"
import { SideNav } from "@/components/layout/side-nav"

export const Route = createFileRoute("/_layout")({
  beforeLoad: () => {
    if (!getToken()) {
      throw redirect({ to: "/login" })
    }
  },
  component: LayoutComponent,
})

function LayoutComponent() {
  const { user, isAdmin, isLoading } = useAuth()

  if (isLoading) {
    return (
      <div className="flex h-screen items-center justify-center">
        <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
      </div>
    )
  }

  return (
    <div className="flex h-screen">
      <SideNav isAdmin={isAdmin} />
      <div className="flex flex-1 flex-col">
        <Header user={user} />
        <main className="flex-1 overflow-auto p-6">
          <Outlet />
        </main>
      </div>
    </div>
  )
}

import { ClipboardList, History, Settings } from "lucide-react"
import { useTranslation } from "react-i18next"
import { Link, useRouterState } from "@tanstack/react-router"
import { cn } from "@/lib/utils"
import { Separator } from "@/components/ui/separator"

interface SideNavProps {
  isAdmin: boolean
}

interface NavItem {
  icon: React.ComponentType<{ className?: string }>
  labelKey: string
  to: string
}

const userNavItems: NavItem[] = [
  { icon: ClipboardList, labelKey: "nav.myExams", to: "/exams" },
  { icon: History, labelKey: "nav.records", to: "/records" },
]

const adminNavItems: NavItem[] = [
  { icon: Settings, labelKey: "nav.examManagement", to: "/admin/exams" },
]

export function SideNav({ isAdmin }: SideNavProps) {
  const { t } = useTranslation()
  const routerState = useRouterState()
  const currentPath = routerState.location.pathname

  return (
    <aside className="flex h-full w-56 shrink-0 flex-col border-r bg-white">
      <nav className="flex flex-1 flex-col gap-1 p-3">
        {userNavItems.map((item) => (
          <NavLink key={item.to} item={item} currentPath={currentPath} label={t(item.labelKey)} />
        ))}

        {isAdmin && (
          <>
            <Separator className="my-2" />
            {adminNavItems.map((item) => (
              <NavLink key={item.to} item={item} currentPath={currentPath} label={t(item.labelKey)} />
            ))}
          </>
        )}
      </nav>
    </aside>
  )
}

function NavLink({ item, currentPath, label }: { item: NavItem; currentPath: string; label: string }) {
  const isActive = currentPath.startsWith(item.to)
  const Icon = item.icon

  return (
    <Link
      to={item.to}
      className={cn(
        "flex items-center gap-3 rounded-md px-3 py-2 text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground",
        isActive && "bg-accent text-accent-foreground",
      )}
    >
      <Icon className="h-4 w-4" />
      {label}
    </Link>
  )
}

import { LogOut } from "lucide-react"
